import { useLoaderData } from "react-router";
import type { LoaderFunctionArgs, MetaFunction } from "@shopify/remix-oxygen";
import { LocaleLink } from "~/components/LocaleLink";
import { msg } from "~/lib/messages";

export const meta: MetaFunction = () => {
  return [{ title: "Better Store" }];
};

export async function loader({ context }: LoaderFunctionArgs) {
  const { storefront, locale, messages } = context;

  const [{ collections }, { products }] = await Promise.all([
    storefront.query(FEATURED_COLLECTIONS_QUERY, {
      variables: { count: 4 },
    }),
    storefront.query(FEATURED_PRODUCTS_QUERY, {
      variables: { count: 8 },
    }),
  ]);

  return {
    locale,
    messages,
    collections: collections.nodes,
    products: products.nodes,
  };
}

export default function Homepage() {
  const { locale, messages, collections, products } =
    useLoaderData<typeof loader>();
  const common = messages.common;
  const productMessages = messages.products;

  return (
    <div>
      {/* Hero */}
      <section className="bg-gray-900 px-4 py-24 text-center text-white sm:px-6 lg:px-8">
        <h1 className="text-4xl font-bold tracking-tight sm:text-5xl lg:text-6xl">
          {msg(common, "welcome", "Welcome to our store")}
        </h1>
        <p className="mx-auto mt-4 max-w-xl text-lg text-gray-300">
          {msg(
            common,
            "hero_subtitle",
            "Discover our curated collection of products",
          )}
        </p>
        <LocaleLink
          to="/collections/all"
          locale={locale}
          className="mt-8 inline-block rounded-md bg-white px-8 py-3 text-sm font-semibold text-gray-900 shadow-sm hover:bg-gray-100"
        >
          {msg(common, "shop_now", "Shop Now")}
        </LocaleLink>
      </section>

      {/* Featured Products */}
      {products.length > 0 && (
        <section className="mx-auto max-w-7xl px-4 py-16 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between">
            <h2 className="text-2xl font-bold tracking-tight">
              {msg(common, "featured_products", "Featured Products")}
            </h2>
            <LocaleLink
              to="/collections/all"
              locale={locale}
              className="text-sm font-medium text-gray-600 hover:text-gray-900"
            >
              {msg(common, "view_all", "View All")} &rarr;
            </LocaleLink>
          </div>

          <div className="mt-8 grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-4">
            {products.map((product: ProductNode) => {
              const price = product.priceRange.minVariantPrice;
              return (
                <LocaleLink
                  key={product.id}
                  to={`/products/${product.handle}`}
                  locale={locale}
                  className="group"
                >
                  <div className="aspect-square overflow-hidden rounded-xl border border-gray-100 bg-gray-50 transition-shadow group-hover:shadow-md">
                    {product.featuredImage ? (
                      <img
                        src={product.featuredImage.url}
                        alt={product.featuredImage.altText || product.title}
                        className="h-full w-full object-cover transition-transform group-hover:scale-105"
                      />
                    ) : (
                      <div className="flex h-full items-center justify-center text-gray-400">
                        {product.title}
                      </div>
                    )}
                  </div>
                  <div className="mt-3">
                    <h3 className="text-sm font-medium text-gray-900 group-hover:underline">
                      {product.title}
                    </h3>
                    <p className="mt-1 text-sm text-gray-600">
                      {msg(productMessages, "from", "From")}{" "}
                      {price.currencyCode} {parseFloat(price.amount).toFixed(2)}
                    </p>
                  </div>
                </LocaleLink>
              );
            })}
          </div>
        </section>
      )}

      {/* Featured Collections */}
      <section className="mx-auto max-w-7xl px-4 py-16 sm:px-6 lg:px-8">
        <h2 className="text-2xl font-bold tracking-tight">
          {msg(common, "featured_collections", "Featured Collections")}
        </h2>

        <div className="mt-8 grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-4">
          {collections.map((collection: CollectionNode) => (
            <LocaleLink
              key={collection.id}
              to={`/collections/${collection.handle}`}
              locale={locale}
              className="group"
            >
              <div className="aspect-square overflow-hidden rounded-xl border border-gray-100 bg-gray-50 transition-shadow group-hover:shadow-md">
                {collection.image ? (
                  <img
                    src={collection.image.url}
                    alt={collection.image.altText || collection.title}
                    className="h-full w-full object-cover transition-transform group-hover:scale-105"
                  />
                ) : (
                  <div className="flex h-full items-center justify-center text-gray-400">
                    {collection.title}
                  </div>
                )}
              </div>
              <h3 className="mt-3 text-sm font-medium text-gray-900 group-hover:underline">
                {collection.title}
              </h3>
            </LocaleLink>
          ))}
        </div>
      </section>
    </div>
  );
}

interface ProductNode {
  id: string;
  title: string;
  handle: string;
  featuredImage: { url: string; altText: string | null } | null;
  priceRange: {
    minVariantPrice: { amount: string; currencyCode: string };
  };
}

interface CollectionNode {
  id: string;
  title: string;
  handle: string;
  image: { url: string; altText: string | null } | null;
}

const FEATURED_COLLECTIONS_QUERY = `#graphql
  query FeaturedCollections($count: Int!) {
    collections(first: $count, sortKey: UPDATED_AT) {
      nodes {
        id
        title
        handle
        image {
          url
          altText
        }
      }
    }
  }
` as const;

const FEATURED_PRODUCTS_QUERY = `#graphql
  query FeaturedProducts($count: Int!) {
    products(first: $count, sortKey: BEST_SELLING) {
      nodes {
        id
        title
        handle
        featuredImage {
          url
          altText
        }
        priceRange {
          minVariantPrice {
            amount
            currencyCode
          }
        }
      }
    }
  }
` as const;
