import { useState, useRef, useEffect } from "react";
import { useLocation, useNavigate } from "react-router";

interface LocaleInfo {
  label: string;
  nativeLabel: string;
  flag: string;
}

const LOCALE_META: Record<string, LocaleInfo> = {
  en: { label: "English", nativeLabel: "English", flag: "\u{1F1FA}\u{1F1F8}" },
  tr: { label: "Turkish", nativeLabel: "T\u00FCrk\u00E7e", flag: "\u{1F1F9}\u{1F1F7}" },
  es: { label: "Spanish", nativeLabel: "Espa\u00F1ol", flag: "\u{1F1EA}\u{1F1F8}" },
  fr: { label: "French", nativeLabel: "Fran\u00E7ais", flag: "\u{1F1EB}\u{1F1F7}" },
  de: { label: "German", nativeLabel: "Deutsch", flag: "\u{1F1E9}\u{1F1EA}" },
};

interface LocaleSwitcherProps {
  locale: string;
  locales: string[];
}

export function LocaleSwitcher({ locale, locales }: LocaleSwitcherProps) {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);
  const location = useLocation();
  const navigate = useNavigate();

  useEffect(() => {
    function handleClickOutside(e: MouseEvent) {
      if (ref.current && !ref.current.contains(e.target as Node)) {
        setOpen(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  function handleSelect(newLocale: string) {
    setOpen(false);
    const currentPath = location.pathname;
    const pathWithoutLocale = currentPath.replace(/^\/(tr|es|fr|de)/, "") || "/";
    const newPath =
      newLocale === "en"
        ? pathWithoutLocale
        : `/${newLocale}${pathWithoutLocale}`;
    navigate(newPath + location.search);
  }

  const current = LOCALE_META[locale] || {
    label: locale,
    nativeLabel: locale,
    flag: "",
  };

  return (
    <div ref={ref} className="relative">
      <button
        type="button"
        onClick={() => setOpen(!open)}
        className="flex items-center gap-1.5 rounded-lg border border-gray-200 bg-white px-3 py-1.5 text-sm font-medium text-gray-700 shadow-sm transition-colors hover:bg-gray-50"
        aria-label="Select language"
        aria-expanded={open}
      >
        <span className="text-base leading-none">{current.flag}</span>
        <span className="uppercase">{locale}</span>
        <svg
          className={`h-3.5 w-3.5 text-gray-400 transition-transform ${open ? "rotate-180" : ""}`}
          fill="none"
          viewBox="0 0 24 24"
          strokeWidth={2.5}
          stroke="currentColor"
        >
          <path
            strokeLinecap="round"
            strokeLinejoin="round"
            d="M19.5 8.25l-7.5 7.5-7.5-7.5"
          />
        </svg>
      </button>

      {open && (
        <div className="absolute right-0 z-50 mt-1.5 w-44 overflow-hidden rounded-lg border border-gray-200 bg-white shadow-lg">
          {locales.map((loc) => {
            const info = LOCALE_META[loc] || {
              label: loc,
              nativeLabel: loc,
              flag: "",
            };
            const isActive = loc === locale;
            return (
              <button
                key={loc}
                type="button"
                onClick={() => handleSelect(loc)}
                className={`flex w-full items-center gap-2.5 px-3 py-2 text-sm transition-colors hover:bg-gray-50 ${
                  isActive ? "font-semibold text-gray-900" : "text-gray-600"
                }`}
              >
                <span className="text-base leading-none">{info.flag}</span>
                <span className="flex-1 text-left">{info.nativeLabel}</span>
                {isActive && (
                  <svg
                    className="h-4 w-4 text-gray-900"
                    fill="none"
                    viewBox="0 0 24 24"
                    strokeWidth={2.5}
                    stroke="currentColor"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      d="M4.5 12.75l6 6 9-13.5"
                    />
                  </svg>
                )}
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
}
