import { useState } from "react";
import { useLoaderData } from "react-router";
import type { LoaderFunctionArgs, MetaFunction } from "@shopify/remix-oxygen";
import { msg } from "~/lib/messages";

export const meta: MetaFunction<typeof loader> = ({ data }) => {
  return [{ title: data?.product?.title ?? "Product" }];
};

export async function loader({ params, context }: LoaderFunctionArgs) {
  const { storefront, locale, messages } = context;
  const { handle } = params;

  if (!handle) {
    throw new Response("Product handle required", { status: 400 });
  }

  const { product } = await storefront.query(PRODUCT_QUERY, {
    variables: { handle },
  });

  if (!product) {
    throw new Response("Product not found", { status: 404 });
  }

  return { product, locale, messages };
}

export default function ProductPage() {
  const { product, messages } = useLoaderData<typeof loader>();
  const productMessages = messages.products;

  const variants: VariantNode[] = product.variants.nodes;
  const options: OptionNode[] = product.options || [];
  const images: ImageNode[] = product.images?.nodes || [];

  // Initialize selected options from first variant
  const [selectedOptions, setSelectedOptions] = useState<
    Record<string, string>
  >(() => {
    const first = variants[0];
    if (!first) return {};
    const opts: Record<string, string> = {};
    for (const opt of first.selectedOptions) {
      opts[opt.name] = opt.value;
    }
    return opts;
  });

  const [activeImageIndex, setActiveImageIndex] = useState(0);

  // Find matching variant
  const selectedVariant =
    variants.find((v) =>
      v.selectedOptions.every(
        (opt) => selectedOptions[opt.name] === opt.value,
      ),
    ) || variants[0];

  const isAvailable = selectedVariant?.availableForSale ?? false;
  const price = selectedVariant?.price;
  const compareAtPrice = selectedVariant?.compareAtPrice;
  const hasDiscount =
    compareAtPrice && parseFloat(compareAtPrice.amount) > 0 &&
    parseFloat(compareAtPrice.amount) > parseFloat(price?.amount || "0");

  // Use variant image if available, otherwise use gallery
  const displayImages =
    images.length > 0
      ? images
      : product.featuredImage
        ? [product.featuredImage]
        : [];
  const activeImage = displayImages[activeImageIndex] || null;

  function handleOptionChange(optionName: string, value: string) {
    setSelectedOptions((prev) => ({ ...prev, [optionName]: value }));
  }

  return (
    <div className="mx-auto max-w-7xl px-4 py-12 sm:px-6 lg:px-8">
      <div className="grid grid-cols-1 gap-12 lg:grid-cols-2">
        {/* Product Images */}
        <div>
          <div className="aspect-square overflow-hidden rounded-xl bg-gray-100">
            {activeImage ? (
              <img
                src={activeImage.url}
                alt={activeImage.altText || product.title}
                className="h-full w-full object-cover"
              />
            ) : (
              <div className="flex h-full items-center justify-center text-gray-400">
                No image
              </div>
            )}
          </div>

          {/* Thumbnail Gallery */}
          {displayImages.length > 1 && (
            <div className="mt-4 flex gap-3">
              {displayImages.map((img, i) => (
                <button
                  key={img.url}
                  type="button"
                  onClick={() => setActiveImageIndex(i)}
                  className={`h-16 w-16 overflow-hidden rounded-lg border-2 transition-colors ${
                    i === activeImageIndex
                      ? "border-gray-900"
                      : "border-transparent hover:border-gray-300"
                  }`}
                >
                  <img
                    src={img.url}
                    alt={img.altText || `${product.title} ${i + 1}`}
                    className="h-full w-full object-cover"
                  />
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Product Info */}
        <div className="flex flex-col justify-start">
          <h1 className="text-3xl font-bold tracking-tight">
            {product.title}
          </h1>

          {/* Price */}
          {price && (
            <div className="mt-4 flex items-center gap-3">
              <p
                className={`text-2xl font-semibold ${hasDiscount ? "text-red-600" : "text-gray-900"}`}
              >
                {price.currencyCode} {parseFloat(price.amount).toFixed(2)}
              </p>
              {hasDiscount && compareAtPrice && (
                <del className="text-lg text-gray-400">
                  {compareAtPrice.currencyCode}{" "}
                  {parseFloat(compareAtPrice.amount).toFixed(2)}
                </del>
              )}
            </div>
          )}

          {/* Stock Status */}
          <div className="mt-3">
            {isAvailable ? (
              <span className="inline-flex items-center gap-1.5 text-sm text-green-600">
                <span className="h-2 w-2 rounded-full bg-green-500" />
                {msg(productMessages, "in_stock", "In Stock")}
              </span>
            ) : (
              <span className="inline-flex items-center gap-1.5 text-sm text-red-500">
                <span className="h-2 w-2 rounded-full bg-red-400" />
                {msg(productMessages, "sold_out", "Sold Out")}
              </span>
            )}
          </div>

          {/* Variant Options */}
          {options.length > 0 &&
            options.map((option) => {
              // Skip "Title" option with single "Default Title" value
              if (
                option.name === "Title" &&
                option.optionValues.length === 1 &&
                option.optionValues[0].name === "Default Title"
              ) {
                return null;
              }

              return (
                <div key={option.id} className="mt-6">
                  <h3 className="text-sm font-medium text-gray-900">
                    {msg(
                      productMessages,
                      "select_option",
                      "Select",
                    )}{" "}
                    {option.name}
                  </h3>
                  <div className="mt-2 flex flex-wrap gap-2">
                    {option.optionValues.map((val) => {
                      const isSelected =
                        selectedOptions[option.name] === val.name;
                      // Check if this option value leads to an available variant
                      const isOptionAvailable = variants.some(
                        (v) =>
                          v.availableForSale &&
                          v.selectedOptions.some(
                            (so) =>
                              so.name === option.name && so.value === val.name,
                          ),
                      );

                      return (
                        <button
                          key={val.name}
                          type="button"
                          onClick={() =>
                            handleOptionChange(option.name, val.name)
                          }
                          disabled={!isOptionAvailable}
                          className={`rounded-lg border px-4 py-2 text-sm font-medium transition-colors ${
                            isSelected
                              ? "border-gray-900 bg-gray-900 text-white ring-2 ring-gray-900 ring-offset-1"
                              : isOptionAvailable
                                ? "border-gray-200 text-gray-700 hover:border-gray-400"
                                : "border-gray-100 text-gray-300 line-through opacity-40"
                          }`}
                        >
                          {val.name}
                        </button>
                      );
                    })}
                  </div>
                </div>
              );
            })}

          {/* Add to Cart */}
          <button
            disabled={!isAvailable}
            className={`mt-8 w-full rounded-lg px-8 py-3 text-sm font-semibold text-white shadow-sm transition-colors sm:w-auto ${
              isAvailable
                ? "bg-gray-900 hover:bg-gray-800"
                : "cursor-not-allowed bg-gray-400"
            }`}
          >
            {isAvailable
              ? msg(productMessages, "add_to_cart", "Add to Cart")
              : msg(productMessages, "sold_out", "Sold Out")}
          </button>

          {/* Description */}
          {product.description && (
            <div className="mt-10 border-t border-gray-200 pt-8">
              <h2 className="text-lg font-semibold text-gray-900">
                {msg(productMessages, "description", "Description")}
              </h2>
              <p className="mt-3 text-base leading-relaxed text-gray-600">
                {product.description}
              </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

interface ImageNode {
  url: string;
  altText: string | null;
  width?: number;
  height?: number;
}

interface OptionNode {
  id: string;
  name: string;
  optionValues: { name: string }[];
}

interface VariantNode {
  id: string;
  title: string;
  availableForSale: boolean;
  quantityAvailable: number | null;
  selectedOptions: { name: string; value: string }[];
  price: { amount: string; currencyCode: string };
  compareAtPrice: { amount: string; currencyCode: string } | null;
  image: ImageNode | null;
}

const PRODUCT_QUERY = `#graphql
  query Product($handle: String!) {
    product(handle: $handle) {
      id
      title
      handle
      description
      featuredImage {
        url
        altText
        width
        height
      }
      images(first: 5) {
        nodes {
          url
          altText
          width
          height
        }
      }
      options {
        id
        name
        optionValues {
          name
        }
      }
      variants(first: 50) {
        nodes {
          id
          title
          availableForSale
          quantityAvailable
          selectedOptions {
            name
            value
          }
          price {
            amount
            currencyCode
          }
          compareAtPrice {
            amount
            currencyCode
          }
          image {
            url
            altText
            width
            height
          }
        }
      }
    }
  }
` as const;
