import { useLoaderData } from "react-router";
import type { LoaderFunctionArgs, MetaFunction } from "@shopify/remix-oxygen";
import { LocaleLink } from "~/components/LocaleLink";
import { msg } from "~/lib/messages";

export const meta: MetaFunction<typeof loader> = ({ data }) => {
  return [{ title: data?.collection?.title ?? "Collection" }];
};

export async function loader({ params, context }: LoaderFunctionArgs) {
  const { storefront, locale, messages } = context;
  const { handle } = params;

  if (!handle) {
    throw new Response("Collection handle required", { status: 400 });
  }

  const { collection } = await storefront.query(COLLECTION_QUERY, {
    variables: { handle, count: 24 },
  });

  if (!collection) {
    throw new Response("Collection not found", { status: 404 });
  }

  return { collection, locale, messages };
}

export default function CollectionPage() {
  const { collection, locale, messages } = useLoaderData<typeof loader>();
  const productMessages = messages.products;

  return (
    <div className="mx-auto max-w-7xl px-4 py-12 sm:px-6 lg:px-8">
      <h1 className="text-4xl font-bold tracking-tight">{collection.title}</h1>
      {collection.description && (
        <p className="mt-3 max-w-2xl text-base text-gray-500">
          {collection.description}
        </p>
      )}

      <div className="mt-10 grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
        {collection.products.nodes.map((product: ProductNode) => {
          const price = product.priceRange.minVariantPrice;
          return (
            <LocaleLink
              key={product.id}
              to={`/products/${product.handle}`}
              locale={locale}
              className="group"
            >
              <div className="aspect-square overflow-hidden rounded-xl border border-gray-100 bg-gray-50 transition-shadow group-hover:shadow-md">
                {product.featuredImage ? (
                  <img
                    src={product.featuredImage.url}
                    alt={product.featuredImage.altText || product.title}
                    className="h-full w-full object-cover transition-transform group-hover:scale-105"
                  />
                ) : (
                  <div className="flex h-full items-center justify-center text-gray-400">
                    {product.title}
                  </div>
                )}
              </div>
              <div className="mt-3">
                <h3 className="text-sm font-medium text-gray-900 group-hover:underline">
                  {product.title}
                </h3>
                <p className="mt-1 text-sm text-gray-600">
                  {msg(productMessages, "from", "From")}{" "}
                  {price.currencyCode} {parseFloat(price.amount).toFixed(2)}
                </p>
              </div>
            </LocaleLink>
          );
        })}
      </div>

      {collection.products.nodes.length === 0 && (
        <p className="mt-8 text-center text-gray-500">
          {msg(
            productMessages,
            "no_products",
            "No products found in this collection.",
          )}
        </p>
      )}
    </div>
  );
}

interface ProductNode {
  id: string;
  title: string;
  handle: string;
  featuredImage: { url: string; altText: string | null } | null;
  priceRange: {
    minVariantPrice: { amount: string; currencyCode: string };
  };
}

const COLLECTION_QUERY = `#graphql
  query Collection($handle: String!, $count: Int!) {
    collection(handle: $handle) {
      id
      title
      handle
      description
      products(first: $count) {
        nodes {
          id
          title
          handle
          featuredImage {
            url
            altText
          }
          priceRange {
            minVariantPrice {
              amount
              currencyCode
            }
          }
        }
      }
    }
  }
` as const;
